import{_ as e,c as r,o as a,a2 as n}from"./chunks/framework.CIiVzG-O.js";const h=JSON.parse('{"title":"Supported Formats","description":"","frontmatter":{},"headers":[],"relativePath":"guide/formats.md","filePath":"guide/formats.md","lastUpdated":1783609501000}'),i={name:"guide/formats.md"};function o(s,t,l,d,g,c){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="supported-formats" tabindex="-1">Supported Formats <a class="header-anchor" href="#supported-formats" aria-label="Permalink to &quot;Supported Formats&quot;">​</a></h1><p>NueZip supports a wide range of archive formats for both reading and writing. Below is the complete format compatibility matrix.</p><h2 id="format-matrix" tabindex="-1">Format Matrix <a class="header-anchor" href="#format-matrix" aria-label="Permalink to &quot;Format Matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Format</th><th style="text-align:center;">Read</th><th style="text-align:center;">Write (Compress)</th><th style="text-align:center;">Encryption</th><th style="text-align:center;">Multi-Volume</th></tr></thead><tbody><tr><td><strong>ZIP</strong></td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">AES-256</td><td style="text-align:center;">✅</td></tr><tr><td><strong>7-Zip (.7z)</strong></td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">AES-256 (LZMA2)</td><td style="text-align:center;">✅</td></tr><tr><td><strong>TAR</strong></td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td><td style="text-align:center;">✅</td></tr><tr><td><strong>GZIP (.gz)</strong></td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td><strong>BZIP2 (.bz2)</strong></td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td><strong>XZ</strong></td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td><strong>Zstandard (.zst)</strong></td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr><tr><td><strong>RAR</strong></td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅ (read)</td><td style="text-align:center;">✅ (read)</td></tr></tbody></table><blockquote><p><strong>Note</strong>: RAR compression is not supported due to licensing restrictions. NueZip can read RAR archives including multi-volume and encrypted RAR archives.</p></blockquote><h2 id="format-details" tabindex="-1">Format Details <a class="header-anchor" href="#format-details" aria-label="Permalink to &quot;Format Details&quot;">​</a></h2><h3 id="zip" tabindex="-1">ZIP <a class="header-anchor" href="#zip" aria-label="Permalink to &quot;ZIP&quot;">​</a></h3><ul><li><strong>Compression</strong>: Store, Deflate, Deflate64, BZIP2, LZMA, PPMd</li><li><strong>Encryption</strong>: AES-256 (recommended), ZipCrypto (legacy)</li><li><strong>Volume support</strong>: Multi-volume split archives (<code>.zip.001</code>, <code>.zip.002</code>, ...)</li><li><strong>Best for</strong>: Universal compatibility across platforms</li></ul><h3 id="_7-zip" tabindex="-1">7-Zip <a class="header-anchor" href="#_7-zip" aria-label="Permalink to &quot;7-Zip&quot;">​</a></h3><ul><li><strong>Compression</strong>: LZMA2 (default), LZMA, PPMd, BZIP2, Deflate</li><li><strong>Encryption</strong>: AES-256</li><li><strong>Volume support</strong>: Multi-volume split archives</li><li><strong>Best for</strong>: Maximum compression ratio</li></ul><h3 id="tar" tabindex="-1">TAR <a class="header-anchor" href="#tar" aria-label="Permalink to &quot;TAR&quot;">​</a></h3><ul><li><strong>Compression</strong>: Uncompressed, or combined with GZIP/BZIP2/XZ/Zstandard</li><li><strong>Best for</strong>: Unix/Linux archives, preserving file permissions</li></ul><h3 id="gzip-bzip2-xz-zstandard" tabindex="-1">GZIP / BZIP2 / XZ / Zstandard <a class="header-anchor" href="#gzip-bzip2-xz-zstandard" aria-label="Permalink to &quot;GZIP / BZIP2 / XZ / Zstandard&quot;">​</a></h3><ul><li><strong>Standalone</strong> compression formats (single file, no archive bundling)</li><li>Often used in combination with TAR (<code>.tar.gz</code>, <code>.tar.xz</code>, <code>.tar.zst</code>)</li></ul><h3 id="rar" tabindex="-1">RAR <a class="header-anchor" href="#rar" aria-label="Permalink to &quot;RAR&quot;">​</a></h3><ul><li><strong>Read support</strong>: RAR4, RAR5, multi-volume, encrypted</li><li><strong>Repair</strong>: Recovery record and reconstruction</li><li><strong>Write</strong>: Not supported</li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li><strong>For sharing with others</strong>: Use <strong>ZIP</strong> — it&#39;s the most widely compatible format</li><li><strong>For personal archiving</strong>: Use <strong>7-Zip</strong> — best compression ratios, save disk space</li><li><strong>For large files</strong>: Use <strong>Split ZIP</strong> or <strong>Split 7-Zip</strong> to break into manageable volumes</li><li><strong>For sensitive data</strong>: Always enable <strong>AES-256 encryption</strong> with a strong password</li><li>Distinctive round face with big eyes</li></ul>',18)])])}const m=e(i,[["render",o]]);export{h as __pageData,m as default};
